BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "Label" (
	"id"	INTEGER,
	"code"	TEXT,
	"label"	TEXT,
	PRIMARY KEY("id" AUTOINCREMENT)
);
CREATE TABLE IF NOT EXISTS "Matchdata" (
	"id"	INTEGER,
	"Div"	TEXT,
	"Season"	TEXT,
	"Date"	TEXT,
	"DateInt"	INTEGER,
	"HomeTeam"	TEXT,
	"AwayTeam"	TEXT,
	"FTHG"	INTEGER,
	"FTAG"	INTEGER,
	"FTR"	INTEGER,
	"B365H"	TEXT,
	"B365D"	TEXT,
	"B365A"	TEXT,
	PRIMARY KEY("id" AUTOINCREMENT)
);
CREATE TABLE IF NOT EXISTS "StatsData" (
	"id"	INTEGER,
	"DateInt"	INTEGER,
	"Season"	TEXT,
	"Team"	TEXT,
	"AvgTRJ"	REAL,
	"ROI"	REAL,
	"NbrofMatches"	INTEGER,
	"AverageOddResult"	REAL,
	"ROI_10D"	REAL,
	"ROI_5D"	REAL,
	"ROI_3D"	REAL,
	"ROI_2D"	REAL,
	"ROIJJ_D"	REAL,
	"ROID"	REAL,
	"OddD"	REAL,
	"InvOddD"	REAL,
	"Last5Results"	TEXT,
	PRIMARY KEY("id" AUTOINCREMENT)
);
CREATE VIEW "DistinctDivTeamSeason" AS
SELECT 
  d."Div",
  ld."label" AS "DivLabel",
  d."Season",
  ls."label" AS "SeasonLabel",
  json_group_array(DISTINCT d."HomeTeam") AS "Teams"
FROM "Matchdata" d
LEFT JOIN "Label" ld ON ld."code" = d."Div"
LEFT JOIN "Label" ls ON ls."code" = d."Season"
GROUP BY d."Div", d."Season"
ORDER BY d."Div", d."Season";
COMMIT;
